import React, { useState, useEffect } from 'react';

const LiteratureManager = ({ isOpen, onClose, onSave, initialLiterature = [] }) => {
    const [literature, setLiterature] = useState([]);
    const [authors, setAuthors] = useState('');
    const [title, setTitle] = useState('');
    const [year, setYear] = useState('');
    const [publisher, setPublisher] = useState('');

    useEffect(() => {
        if (initialLiterature && initialLiterature.length > 0) {
            setLiterature(initialLiterature);
        }
    }, [initialLiterature]);

    const addItem = () => {
        if (!authors || !title) {
            alert('Заполните авторов и название');
            return;
        }

        const newItem = {
            id: Date.now(),
            authors,
            title,
            year,
            publisher
        };

        setLiterature([...literature, newItem]);
        setAuthors('');
        setTitle('');
        setYear('');
        setPublisher('');
    };

    const deleteItem = (id) => {
        if (window.confirm('Удалить источник?')) {
            setLiterature(literature.filter(item => item.id !== id));
        }
    };

    const handleSave = () => {
        onSave(literature);
        onClose();
    };

    if (!isOpen) return null;

    return (
        <div style={styles.overlay}>
            <div style={styles.modal}>
                {/* Заголовок */}
                <div style={styles.header}>
                    <h2>📚 Список литературы</h2>
                    <button onClick={onClose} style={styles.closeBtn}>✕</button>
                </div>

                {/* Форма добавления */}
                <div style={styles.form}>
                    <input
                        type="text"
                        placeholder="Авторы (например: Иванов И.И.)"
                        value={authors}
                        onChange={(e) => setAuthors(e.target.value)}
                        style={styles.input}
                    />
                    <input
                        type="text"
                        placeholder="Название статьи/книги"
                        value={title}
                        onChange={(e) => setTitle(e.target.value)}
                        style={styles.input}
                    />
                    <input
                        type="text"
                        placeholder="Год"
                        value={year}
                        onChange={(e) => setYear(e.target.value)}
                        style={styles.input}
                    />
                    <input
                        type="text"
                        placeholder="Издательство (необязательно)"
                        value={publisher}
                        onChange={(e) => setPublisher(e.target.value)}
                        style={styles.input}
                    />
                    <button onClick={addItem} style={styles.addBtn}>+ Добавить источник</button>
                </div>

                {/* Список литературы */}
                {literature.length > 0 && (
                    <div style={styles.list}>
                        <h3>Список источников ({literature.length})</h3>
                        {literature.map((item, index) => (
                            <div key={item.id} style={styles.item}>
                                <div style={styles.itemText}>
                                    <strong>{index + 1}.</strong> {item.authors}. {item.title}. {item.year}. {item.publisher}
                                </div>
                                <button onClick={() => deleteItem(item.id)} style={styles.deleteBtn}>🗑️</button>
                            </div>
                        ))}
                    </div>
                )}

                {/* Кнопки */}
                <div style={styles.footer}>
                    <button onClick={onClose} style={styles.cancelBtn}>Отмена</button>
                    <button onClick={handleSave} style={styles.saveBtn}>Сохранить ({literature.length})</button>
                </div>
            </div>
        </div>
    );
};

const styles = {
    overlay: {
        position: 'fixed',
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        backgroundColor: 'rgba(0,0,0,0.5)',
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        zIndex: 1000
    },
    modal: {
        backgroundColor: 'white',
        borderRadius: '10px',
        width: '500px',
        maxWidth: '90%',
        maxHeight: '80vh',
        display: 'flex',
        flexDirection: 'column',
        boxShadow: '0 5px 15px rgba(0,0,0,0.3)'
    },
    header: {
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        padding: '15px 20px',
        borderBottom: '1px solid #ddd',
        backgroundColor: '#f39c12',
        borderRadius: '10px 10px 0 0',
        color: 'white'
    },
    closeBtn: {
        background: 'none',
        border: 'none',
        fontSize: '20px',
        cursor: 'pointer',
        color: 'white'
    },
    form: {
        padding: '20px',
        borderBottom: '1px solid #eee'
    },
    input: {
        width: '100%',
        padding: '8px 12px',
        marginBottom: '10px',
        border: '1px solid #ddd',
        borderRadius: '5px',
        fontSize: '14px',
        boxSizing: 'border-box'
    },
    addBtn: {
        width: '100%',
        padding: '10px',
        backgroundColor: '#27ae60',
        color: 'white',
        border: 'none',
        borderRadius: '5px',
        cursor: 'pointer',
        fontSize: '14px'
    },
    list: {
        flex: 1,
        overflowY: 'auto',
        padding: '20px'
    },
    item: {
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        padding: '10px',
        marginBottom: '10px',
        backgroundColor: '#f9f9f9',
        borderRadius: '5px',
        border: '1px solid #eee'
    },
    itemText: {
        flex: 1,
        fontSize: '14px',
        lineHeight: 1.4
    },
    deleteBtn: {
        background: 'none',
        border: 'none',
        cursor: 'pointer',
        fontSize: '18px',
        marginLeft: '10px',
        color: '#e74c3c'
    },
    footer: {
        display: 'flex',
        justifyContent: 'flex-end',
        gap: '10px',
        padding: '15px 20px',
        borderTop: '1px solid #ddd'
    },
    cancelBtn: {
        padding: '8px 20px',
        backgroundColor: '#95a5a6',
        color: 'white',
        border: 'none',
        borderRadius: '5px',
        cursor: 'pointer'
    },
    saveBtn: {
        padding: '8px 20px',
        backgroundColor: '#f39c12',
        color: 'white',
        border: 'none',
        borderRadius: '5px',
        cursor: 'pointer'
    }
};

export default LiteratureManager;
